Fixed version:

```typescript
function findMax(arr: number[]): number {
  if (arr.length === 0) {
    throw new Error('Array must not be empty');
  }

  let max = -Infinity;

  for (const n of arr) {
    if (n > max) {
      max = n;
    }
  }

  return max;
}
```

